package main

import ("fmt"; "log"; "net/http"; "os")
func NewHandler() http.Handler{a:=&API{db:seed()};m:=http.NewServeMux();for _,r:=range []struct{m string;p string;h HandlerFunc}{{"GET","/healthz",a.health},{"GET","/me",a.me},{"POST","/projects",a.createProject},{"GET","/projects",a.listProjects},{"GET","/projects/{id}",a.getProject},{"PATCH","/projects/{id}",a.patchProject},{"DELETE","/projects/{id}",a.deleteProject},{"GET","/projects/{id}/tasks",a.listProjectTasks},{"POST","/projects/{id}/tasks",a.createTask},{"POST","/projects/{id}/shares",a.createShare},{"POST","/shares/{id}/accept",a.acceptShare},{"GET","/tasks/{id}",a.getTask},{"PATCH","/tasks/{id}",a.patchTask},{"DELETE","/tasks/{id}",a.deleteTask},{"POST","/tasks/{id}/comments",a.addComment},{"GET","/tasks/{id}/comments",a.listComments},{"POST","/tasks/{id}/attachments",a.uploadAttachment},{"GET","/tasks/{id}/attachments/{path...}",a.getAttachment},{"GET","/projects/{id}/export",a.exportProject},{"POST","/projects/{id}/share",a.shareProject},{"POST","/projects/{id}/duplicate",a.duplicateProject},{"POST","/projects/{id}/snapshot",a.snapshotProject},{"POST","/projects/{id}/share-link",a.shareLink},{"POST","/projects/{id}/generate-report",a.generateReport},{"GET","/search/tasks",a.searchTasks},{"POST","/tasks/{id}/notify-webhook",a.notifyWebhook},{"GET","/admin/audit-log",a.auditLog},{"GET","/admin/reports/summary",a.reportsSummary},{"GET","/debug/users",a.debugUsers},{"GET","/debug/config",a.debugConfig},{"GET","/debug/env",a.debugEnv},{"GET","/debug/dump",a.debugDump},{"GET","/debug/boom",a.debugBoom},{"GET","/api/v1/tasks",a.legacyTasks},{"GET","/api/v1/projects",a.legacyProjects},{"POST","/ops/replay",a.opsReplay},{"GET","/ops/cursor/{id}",a.opsCursor}}{m.HandleFunc(r.m+" "+r.p,r.h)};return recoverer(m)}
func main(){addr:=":8080";if p:=os.Getenv("PORT");p!=""{addr=":"+p};log.Printf("projecthub listening on %s",addr);log.Fatal(http.ListenAndServe(addr,NewHandler()))}
func recoverer(next http.Handler) http.Handler{return http.HandlerFunc(func(w http.ResponseWriter,r *http.Request){defer func(){if x:=recover();x!=nil{writeJSON(w,500,map[string]any{"error":fmt.Sprintf("panic in /repo/projecthub/wire.go: %v\ngoroutine stack runtime.go",x)})}}();next.ServeHTTP(w,r)})}
